protected StringBuffer renderWrappedText(StringBuffer sb, int width,
                                         int nextLineTabStop, String text)
{
    int pos = findWrapPos(text, width, 0);

    if (pos == -1)
    {
        sb.append(rtrim(text));

        return sb;
    }
    sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);

    if (nextLineTabStop >= width)
    {
        // stops infinite loop happening
        throw new IllegalStateException("Total width is less than the width of the argument and indent " +
                                        "- no room for the description");
    }

    // all following lines must be padded with nextLineTabStop space
    // characters
    final String padding = createPadding(nextLineTabStop);

    while (true)
    {
        text = padding + text.substring(pos).trim();
        pos = findWrapPos(text, width, 0);

        if (pos == -1)
        {
            sb.append(text);

            return sb;
        }

        if ( (text.length() > width) && (pos == nextLineTabStop - 1) )
        {
            // If nextLineTabStop is too large for the width, we need to force a break
            // even if it's not at a whitespace boundary
            if (nextLineTabStop >= width) {
                pos = width;
            } else {
                // If pos is at the beginning of the actual text (after padding), 
                // and the padding already takes up most of the width, we should 
                // break at the width position or find an appropriate break point
                pos = Math.max(nextLineTabStop, pos);
                if (pos >= width) {
                    // If the padding alone is already taking most/all of the width,
                    // we need to just take whatever we can fit
                    pos = Math.min(text.length(), width);
                }
            }
        }

        sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);

        // Check if we've consumed all text
        text = text.substring(pos).trim();
        if (text.length() == 0) {
            return sb;
        }
    }
}

