while (true)
{
    text = padding + text.substring(pos).trim();
    pos = findWrapPos(text, width, 0);

    if (pos == -1)
    {
        sb.append(text);

        return sb;
    }

    if ( (text.length() > width) && (pos == nextLineTabStop - 1) )
    {
        // The original bug was here - when nextLineTabStop-1 equals the wrap pos,
        // it means findWrapPos couldn't find a proper wrap point after the padding.
        // Instead of blindly setting pos = width which might cause character-by-char
        // printing, check if we can make progress by moving past the problematic point
        int originalPos = pos;
        pos = Math.min(width, text.length());

        // Ensure we make progress to avoid infinite loops
        if (pos <= originalPos) {
            pos = originalPos + 1;
            if (pos > text.length()) {
                sb.append(text);
                return sb;
            }
        }
    }

    sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);

    // Update text to the remainder after the current line
    text = text.substring(pos).trim();

    // If no more text, we're done
    if (text.length() == 0) {
        return sb;
    }
}

