import java.io.StringWriter;
import java.io.PrintWriter;

import org.apache.commons.cli.HelpFormatter;
import org.apache.commons.cli.Option;
import org.apache.commons.cli.Options;

public class TestReproduction {
    public static void main(String[] args) {
        Options options = new Options();
        options.addOption("x", "extralongarg", false, "This description is Long." );
        HelpFormatter formatter = new HelpFormatter();
        StringWriter sw = new StringWriter();
        formatter.printHelp(new PrintWriter(sw), 22, TestReproduction.class.getName(), "Header", options, 0, 5, "Footer");
        String output = sw.toString();
        System.out.println("Actual output:");
        System.out.println("[" + output + "]");
        System.out.println("End of output");

        System.out.println("\nExpected output:");
        String expected = "usage:\n" +
                          "       org.apache.comm\n" +
                          "       ons.cli.bug.Bug\n" +
                          "       CLI162Test\n" +
                          "Header\n" +
                          "-x,--extralongarg\n" +
                          "                     T\n" +
                          "                     h\n" +
                          "                     i\n" +
                          "                     s\n" +
