{
    text = padding + text.substring(pos).trim();
    pos = findWrapPos(text, width, 0);

    if (pos == -1)
    {
        sb.append(text);

        return sb;
    }

    if ( (text.length() > width) && (pos == nextLineTabStop - 1) )
    {
        // ORIGINAL FIX: The issue was pos = width when width is small
        // This can cause issues when the padding + width combination leaves no room for content
        // Calculate the position more carefully
        if (nextLineTabStop + 1 < text.length()) {
            pos = nextLineTabStop + 1;
        } else {
            pos = text.length(); // Use the full remaining text
        }
    }

    sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);

    // Update text to the remainder after the current line
    text = text.substring(pos).trim();

    // If no more text, we're done
    if (text.length() == 0) {
        return sb;
    }
}

